mapper.select:
SELECT * FROM chat_message
WHERE session_id = #{sessionId}

    AND id < #{cursor}

ORDER BY id DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM chat_message
WHERE session_id = #{sessionId}
AND id IN (
    SELECT id FROM (
        SELECT id FROM chat_message
        WHERE session_id = #{sessionId}
        ORDER BY id ASC
        LIMIT 1000
    ) AS old_messages
    WHERE (SELECT COUNT(*) FROM chat_message WHERE session_id = #{sessionId}) > #{keepCount}
)
LIMIT 100
